import unittest

from slug import slugify


class SlugTests(unittest.TestCase):
    def test_spaces(self): self.assertEqual(slugify("Hello World"), "hello-world")
    def test_punctuation(self): self.assertEqual(slugify("Hello, World!"), "hello-world")
    def test_repeated_separators(self): self.assertEqual(slugify("a -- b"), "a-b")
    def test_unicode(self): self.assertEqual(slugify("Tromsø Guide"), "tromsø-guide")
